class ConversationManager:
    def __init__(self, system_prompt: str, max_turns: int = 20):
        self.system = system_prompt
        self.history = []
        self.max_turns = max_turns

    def chat(self, user_message: str) -> str:
        self.history.append(
            {'role': 'user', 'content': user_message}
        )
        # Trim: keep only last N turns to avoid context overflow
        if len(self.history) > self.max_turns * 2:
            self.history = self.history[-(self.max_turns * 2):]

        response = client.messages.create(
            model='claude-sonnet-4-6-20260101',
            max_tokens=1024,
            system=self.system,
            messages=self.history
        )
        reply = response.content[0].text
        self.history.append(
            {'role': 'assistant', 'content': reply}
        )
        return reply

# Usage
mgr = ConversationManager(system_prompt='You are a helpful assistant.')
print(mgr.chat('Hello!'))       # turn 1
print(mgr.chat('Tell me more')) # remembers context from turn 1

def ab_test(prompt_a_fn, prompt_b_fn,
             inputs: list, n_runs: int = 3) -> dict:
    scores = {'a': [], 'b': []}
    for inp in inputs:
        for fn, key in [(prompt_a_fn, 'a'), (prompt_b_fn, 'b')]:
            for _ in range(n_runs):
                resp = call_claude(fn(inp))
                score = rate_output(inp, resp)  # your scoring fn
                scores[key].append(score)

    avg_a, avg_b = mean(scores['a']), mean(scores['b'])
    winner = 'A' if avg_a > avg_b else 'B'
    print(f'Prompt A: {avg_a:.2f}/5   Prompt B: {avg_b:.2f}/5')
    print(f'Winner: Prompt {winner} (+{abs(avg_a-avg_b):.2f} points)')
    return {'winner': winner, 'scores': scores}
